  source_date_range
)
SELECT
  rq.id,
  p.id,
  rq.symbol,
  'KRX',
  '1d',
  rq.difficulty,
  'sideways'::market_regime,
  rq.base_date,
  rq.chart_data,
  rq.actual_next_candles,
  rq.correct_answer,
  rq.ai_explanation,
  rq.rule_score,
  0.7000,
  rq.pattern_evidence,
  rq.pattern_score_breakdown,
  false,
  'Yahoo Finance chart API',
  rq.source_url,
  rq.source_symbol,
  rq.source_exchange,
  rq.source_date_range
FROM real_questions rq
CROSS JOIN pattern_row p
